import React from 'react';
import clsx from 'clsx';
import { isFunction } from '../../../../util';
import type { PickerTriggerProps } from '../interface';
import { useCssScope, useDirection } from '../../../../config-provider/hooks';
import { usePopperSidecar } from '../../../../config-provider/hooks/usePopperSidecar';
import type { PopperShowActionType } from '../../popper';
import { SlideUpDownTransition } from '../../transition/SlideUpDownTransition';
import { usePopupPortalContainer } from '@universe-design/react-provider';

const PickerTrigger = function <DateType>(props: PickerTriggerProps<DateType>) {
  const { disabled, open, children, dropdownClassName, popupStyle, popupElement, setOpened, getPopupContainer } = props;

  const triggerElementEnable = Boolean(isFunction(children) || children) && !disabled;
  const cssScope = useCssScope('picker');
  const prefixCls = cssScope();
  const Popper = usePopperSidecar();

  const showAction: PopperShowActionType[] = triggerElementEnable ? ['click'] : [];
  const direction = useDirection();

  const ctxGetPopupContainer = usePopupPortalContainer();

  const getPickerPopupContainer = (triggerNode: HTMLElement): HTMLElement => {
    const _getPopupContainer = getPopupContainer ?? ctxGetPopupContainer;
    return _getPopupContainer(triggerNode);
  };

  return (
    <Popper
      action={undefined}
      showAction={showAction}
      hideAction={[]}
      destroyOnHide
      popupStyle={popupStyle}
      getPopupContainer={getPickerPopupContainer}
      prefixCls={prefixCls}
      popupPlacement={direction === 'rtl' ? 'bottomRight' : 'bottomLeft'}
      visible={open}
      popupClassName={clsx(dropdownClassName, `${prefixCls}-dropdown`)}
      onVisibleChange={setOpened}
      popup={popupElement}
      popupMotion="slide-up"
      enableRestoreFocus={false}
      initialFocus={null}
      {...{
        showArrow: false,
        arrowHasStroke: false,
        Transition: SlideUpDownTransition,
        enableMaxHeight: false,
      }}
      defaultMainAxisOffsetWithoutArrow={4}
    >
      {children}
    </Popper>
  );
};

export default PickerTrigger;
